// src/app/module/Payment/payment.service.ts
import httpStatus from "http-status";
import Stripe from "stripe";
var stripe = new Stripe(process.env.STRIPE_SECRET_KEY, {});
var createPaymentIntent = async (userEmail, eventId) => {
  const user = await prisma.user.findUnique({ where: { email: userEmail } });
  if (!user) {
    throw new AppError(httpStatus.NOT_FOUND, "User not found");
  }
  const event = await prisma.event.findUnique({ where: { id: eventId } });
  if (!event) {
    throw new AppError(httpStatus.NOT_FOUND, "Event not found");
  }
  if (event.fee <= 0) {
    throw new AppError(httpStatus.BAD_REQUEST, "Event is free");
  }
  const amount = Math.round(event.fee * 100);
  const paymentIntent = await stripe.paymentIntents.create({
    amount,
    currency: "usd",
    // default to USD
    metadata: {
      userId: user.id,
      eventId: event.id
    }
  });
  const payment = await prisma.payment.create({
    data: {
      amount: event.fee,
      status: "UNPAID",
      transactionId: paymentIntent.id,
      userId: user.id,
      eventId: event.id
    }
  });
  return {
    clientSecret: paymentIntent.client_secret,
    transactionId: payment.transactionId
  };
};
var handleStripeWebhook = async (event) => {
  if (event.type === "payment_intent.succeeded") {
    const paymentIntent = event.data.object;
    const transactionId = paymentIntent.id;
    const payment = await prisma.payment.findUnique({ where: { transactionId } });
    if (!payment) {
      console.error(`Payment record not found for transaction: ${transactionId}`);
      return;
    }
    await prisma.payment.update({
      where: { transactionId },
      data: { status: "PAID" }
    });
    await prisma.participant.updateMany({
      where: {
        userId: payment.userId,
        eventId: payment.eventId
      },
      data: {
        payment: "PAID"
      }
    });
    await prisma.invitation.updateMany({
      where: {
        userId: payment.userId,
        eventId: payment.eventId
      },
      data: {
        payment: "PAID"
      }
    });
  }
};
var confirmPayment = async (transactionId) => {
  const paymentIntent = await stripe.paymentIntents.confirm(transactionId, {
    payment_method: "pm_card_visa",
    return_url: "http://localhost:5000"
  });
  if (paymentIntent.status === "succeeded" || paymentIntent.status === "requires_action" || paymentIntent.status === "processing") {
    const payment = await prisma.payment.findUnique({ where: { transactionId } });
    if (!payment) {
      throw new AppError(httpStatus.NOT_FOUND, "Payment record not found");
    }
    await prisma.payment.update({
      where: { transactionId },
      data: { status: "PAID" }
    });
    await prisma.participant.updateMany({
      where: { userId: payment.userId, eventId: payment.eventId },
      data: { payment: "PAID" }
    });
    await prisma.invitation.updateMany({
      where: { userId: payment.userId, eventId: payment.eventId },
      data: { payment: "PAID" }
    });
    return { status: "PAID" };
  } else {
    throw new AppError(httpStatus.BAD_REQUEST, "Payment confirmation failed");
  }
};
var PaymentService = {
  createPaymentIntent,
  handleStripeWebhook,
  confirmPayment
};

